  /* Run your local dev server before starting the tests */
  webServer: {
    command: 'npx http-server --port 3099 dist',
    url: 'http://localhost:3099',
    reuseExistingServer: !process.env.CI,
  },

  snapshotDir: './playwright/snapshots',
});

